'use client';

import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/components/ui/accordion';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import type { DetectLogAnomaliesOutput } from '@/ai/flows/detect-log-anomalies';
import { Lightbulb, Wrench } from 'lucide-react';

type Solution = DetectLogAnomaliesOutput['solutions'][0];

interface SolutionSuggestionsProps {
  solutions: Solution[];
}

export function SolutionSuggestions({ solutions }: SolutionSuggestionsProps) {
  if (!solutions || solutions.length === 0) {
    return null;
  }

  return (
    <Card>
      <CardHeader>
        <div className="flex items-center gap-3">
            <Wrench className="h-6 w-6 text-accent" />
            <CardTitle>AI-Powered Solution Suggestions</CardTitle>
        </div>
        <CardDescription>Actionable recommendations from our AI to address detected issues.</CardDescription>
      </CardHeader>
      <CardContent>
        <Accordion type="single" collapsible className="w-full">
          {solutions.map((solution, index) => (
            <AccordionItem value={`item-${index}`} key={index}>
              <AccordionTrigger className="text-base hover:no-underline">
                <div className="flex items-center gap-3 text-left">
                    <Lightbulb className="h-5 w-5 text-accent flex-shrink-0" />
                    <span className="font-semibold">{solution.heading}</span>
                </div>
              </AccordionTrigger>
              <AccordionContent>
                <ol className="list-decimal space-y-2 py-2 pl-6 pr-2 text-sm text-foreground/80">
                  {solution.steps.map((step, stepIndex) => (
                    <li key={stepIndex} className="pl-1 leading-relaxed">{step}</li>
                  ))}
                </ol>
              </AccordionContent>
            </AccordionItem>
          ))}
        </Accordion>
      </CardContent>
    </Card>
  );
}
