import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import type { LogEntry } from '@/types';
import { AnomaliesSummary } from './AnomaliesSummary';
import { LogSummary } from './LogSummary';
import { LogAnalysisCharts } from './LogAnalysisCharts';
import { LogViewer } from './LogViewer';
import { AlertConfiguration } from './AlertConfiguration';
import { SolutionSuggestions } from './SolutionSuggestions';
import type { DetectLogAnomaliesOutput } from '@/ai/flows/detect-log-anomalies';
import { AlertTriangle, Bell, Bot, GanttChartSquare, List, ShieldAlert, Siren } from 'lucide-react';
import { StatCard } from './StatCard';


interface AnalysisDashboardProps {
  logs: LogEntry[];
  anomalySummary: string;
  logSummary: string;
  anomalySolutions: DetectLogAnomaliesOutput['solutions'];
}

export function AnalysisDashboard({ logs, anomalySummary, logSummary, anomalySolutions }: AnalysisDashboardProps) {
  const stats = {
    total: logs.length,
    errors: logs.filter(log => log.level === 'ERROR').length,
    warnings: logs.filter(log => log.level === 'WARN').length,
    anomalies: anomalySolutions.length,
  };

  return (
    <Tabs defaultValue="overview" className="w-full">
      <TabsList className="grid w-full grid-cols-3">
        <TabsTrigger value="overview">
          <GanttChartSquare className="mr-2 h-4 w-4" />
          Overview
        </TabsTrigger>
        <TabsTrigger value="logs">
          <List className="mr-2 h-4 w-4" />
          Log Explorer
        </TabsTrigger>
        <TabsTrigger value="alerts">
          <Bell className="mr-2 h-4 w-4" />
          Alerting
        </TabsTrigger>
      </TabsList>

      <TabsContent value="overview" className="space-y-6 mt-6">
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
            <StatCard title="Total Logs" value={stats.total.toLocaleString()} icon={List} />
            <StatCard title="Errors" value={stats.errors.toLocaleString()} icon={AlertTriangle} variant="destructive" />
            <StatCard title="Warnings" value={stats.warnings.toLocaleString()} icon={Siren} variant="warning" />
            <StatCard title="Anomalies" value={stats.anomalies.toLocaleString()} icon={ShieldAlert} variant="destructive" />
        </div>

        <div className="grid gap-6 md:grid-cols-2">
          <AnomaliesSummary summary={anomalySummary} />
          <LogSummary summary={logSummary} />
        </div>
        
        <SolutionSuggestions solutions={anomalySolutions} />

        <LogAnalysisCharts logs={logs} />
      </TabsContent>

      <TabsContent value="logs" className="mt-6">
          <LogViewer logs={logs} />
      </TabsContent>
      
      <TabsContent value="alerts" className="mt-6">
        <AlertConfiguration />
      </TabsContent>
    </Tabs>
  );
}
